let child: ChildProcess;
try {
  child = exec(
    cmd,
    { cwd: cfg.getTargetDir(), timeout: 5000, maxBuffer: 1024 * 10 },
    (error, stdout) => {
      if (gen !== generationRef.current) return; // stale
      activeChildRef.current = undefined;
      if (!error && stdout) {
        // Strip only the trailing newline to preserve intentional whitespace.
        const line = stdout.replace(/\r?\n$/, '').split(/\r?\n/, 1)[0];
        setOutput(line || null);
      } else {
        setOutput(null);
      }
    },
  );
} catch (error) {
  debugLog.error(
    'statusline command failed to start:',
    getErrorMessage(error),
  );
  activeChildRef.current = undefined;
  setOutput(null);
  return;
}

activeChildRef.current = child;

// Pass structured JSON context via stdin.
// Guard against the child exiting or closing stdin before we finish writing.
if (child.stdin) {
  child.stdin.on('error', (err) => {
    if (!isIgnorableStdinError(err)) {
      debugLog.error('statusline stdin error:', err.message);
    }
  });
  try {
    child.stdin.write(JSON.stringify(input));
    child.stdin.end();
  } catch (error) {
    if (!isIgnorableStdinError(error)) {
      debugLog.error(
        'statusline stdin write error:',
        getErrorMessage(error),
      );
    }
  }
}

